import{_ as e,o,c as a,ah as r}from"./chunks/framework.DsjyFzT5.js";const d="/assets/chrome-plugin-timer.CMwfgfZK.png",g=JSON.parse('{"title":"Chrome概览","description":"","frontmatter":{"title":"Chrome概览","date":"2022-01-01T00:00:00.000Z","category":"Chrome","tags":["ide-skill","Chrome"]},"headers":[],"relativePath":"_post/ide-skill/chrome/index.md","filePath":"_post/ide-skill/chrome/index.md"}'),i={name:"_post/ide-skill/chrome/index.md"};function l(n,t,h,c,s,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="chrome概览" tabindex="-1">Chrome概览 <a class="header-anchor" href="#chrome概览" aria-label="Permalink to &quot;Chrome概览&quot;">​</a></h1><h2 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to &quot;快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">快捷键</th><th style="text-align:center;">描述</th></tr></thead><tbody><tr><td style="text-align:center;">cmd+shift+f</td><td style="text-align:center;">切换全屏</td></tr><tr><td style="text-align:center;">cmd+shift+b</td><td style="text-align:center;">显示、隐藏书签栏</td></tr></tbody></table><h2 id="插件" tabindex="-1">插件 <a class="header-anchor" href="#插件" aria-label="Permalink to &quot;插件&quot;">​</a></h2><ul><li>Timer: 倒计时提醒，帮助定制时间计划 浏览器输入 <code>timer + Tab + 倒计时分钟数</code>,固定插件后才可显示剩余时间 <img src="'+d+'" alt="timer"></li><li>Cookie-Editor cookie导出 导入</li><li>油猴</li><li>繪畫工具和屏幕截圖：取色器，画草稿</li><li>Quick QRCode：二维码生成</li></ul><h2 id="调试" tabindex="-1">调试 <a class="header-anchor" href="#调试" aria-label="Permalink to &quot;调试&quot;">​</a></h2><ul><li><a href="./Advent-calendar-for-front-end-developers-summary">调试技巧</a></li></ul><h2 id="仅用浏览器如何查看图片真实大小" tabindex="-1">仅用浏览器如何查看图片真实大小 <a class="header-anchor" href="#仅用浏览器如何查看图片真实大小" aria-label="Permalink to &quot;仅用浏览器如何查看图片真实大小&quot;">​</a></h2><p>仅用浏览器内置的开发者工具即可查看网络图片的真实尺寸，无需额外插件。以下为常用方法：</p><p>| 方法 | 操作步骤 | 关键属性 / 位置 | 说明 |</p><table tabindex="0"><thead><tr><th><strong>元素面板查看 natural 属性</strong></th><th>1. 按 <strong>F12</strong> 打开开发者工具2. 选中 <code>&lt;img&gt;</code> 元素3. 在右侧 &quot;属性 / Properties&quot; 中查找 <code>naturalWidth</code>、<code>naturalHeight</code></th><th><code>naturalWidth</code>、<code>naturalHeight</code></th><th>直接读取图片文件的像素尺寸，不受 CSS 缩放影响</th></tr></thead><tbody><tr><td><strong>控制台命令</strong></td><td>1. 选中图片 <code>&lt;img&gt;</code> 元素2. 在控制台输入 <code>$0.naturalWidth + &#39;x&#39; + $0.naturalHeight</code></td><td><code>$0</code> 表示当前选中元素</td><td>快速获取并输出宽 × 高字符串</td></tr><tr><td><strong>网络面板查看响应头</strong></td><td>1. 切换到 &quot;网络 / Network&quot;2. 刷新页面并定位图片资源3. 查看 &quot;响应头 / Response Headers&quot; 中的 <code>Content-Length</code></td><td><code>Content-Length</code>（字节）</td><td>可获取文件大小，单位字节</td></tr><tr><td><strong>网络面板查看预览信息</strong></td><td>1. 在 &quot;网络 / Network&quot; 选中图片2. 查看 &quot;预览 / Preview&quot; 或 &quot;媒体 / Media&quot;</td><td>宽、高数值</td><td>多数浏览器会直接显示像素尺寸</td></tr></tbody></table>',11)])])}const _=e(i,[["render",l]]);export{g as __pageData,_ as default};
